import React, { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import './ProductPage.css';

// ── SIMULATED PRODUCT DETAILED REPOSITORY MODEL ──
const MOCK_PRODUCT_DATABASE = {
  'prod-101': {
    name: "Custom Cloud Enterprise Resource Planning Premium Suite Pack",
    price: "₹45,000 / Module",
    description: "An end-to-end industry scale architecture deployment mapping accounting ledger automation, supply-chain routing logs, automated human asset pipelines, and telemetry performance tracking protocols.",
    specs: ["Cloud Native Deployment Architecture", "Advanced End-to-End Cryptographic Ledger Verification", "Real-Time Analytical Forecasting Telemetry Engine"],
    media: [
      'https://images.unsplash.com/photo-1551434678-e076c223a692?auto=format&fit=crop&w=800&q=80',
      'https://images.unsplash.com/photo-1460925895917-afdab827c52f?auto=format&fit=crop&w=800&q=80',
      'https://images.unsplash.com/photo-1504868584819-f8e8b4b6d7e3?auto=format&fit=crop&w=800&q=80'
    ]
  },
  'prod-102': {
    name: "E-Commerce Framework Implementation",
    price: "₹25,000 Startup Flat Rate",
    description: "Turnkey headless commerce architecture deployments engineered utilizing modern reactive component design blocks.",
    specs: ["Sub 200ms Server Side Render Generation", "Integrated Local Payment Aggregations Gateway Ports"],
    media: [
      'https://images.unsplash.com/photo-1563013544-824ae1d704d3?auto=format&fit=crop&w=800&q=80',
      'https://images.unsplash.com/photo-1516321318423-f06f85e504b3?auto=format&fit=crop&w=800&q=80'
    ]
  }
};

const MOCK_SIDEBAR_FALLBACK = {
  relatedCategories: [
    { id: 'cat-s1', name: 'SaaS Architecture Framework Enterprise Tools' },
    { id: 'cat-s2', name: 'Cloud Integration Providers' }
  ],
  relatedKeywords: ['CloudERP', 'NextJsHeadless', 'AutomatedOperations']
};

export default function ProductPage() {
  const { city, company, productId } = useParams();
  const navigate = useNavigate();
  
  // Resolve product database item lookup tracking node parameters
  const productEntity = MOCK_PRODUCT_DATABASE[productId] || MOCK_PRODUCT_DATABASE['prod-101'];
  const [selectedImgIdx, setSelectedImgIdx] = useState(0);

  return (
    <div className="product-page">
      <div className="container product-page-layout">
        <div className="row product-page-layout-row">

          {/* ── LEFT COLUMN AREA: MAIN PRODUCT PROFILE WORKSPACE ── */}
          <div className="col-lg-8 product-profile-scrollable-container">
            
            <div className="breadcrumb-trail-nav-dock">
              {city} &gt; {company} &gt; Products &gt; <span className="trail-active-node">{productEntity.name}</span>
            </div>

            {/* Core Segment Split Card */}
            <div className="product-profile-master-card">
              <div className="row asset-spec-split-grid">
                
                {/* Visualizer Frame Box Segment (Switcher Dock at Bottom) */}
                <div className="col-md-6 product-visualizer-left-cell">
                  <div className="primary-big-showcase-frame">
                    <img src={productEntity.media[selectedImgIdx]} alt={productEntity.name} className="big-showcase-img" />
                  </div>
                  
                  {/* Dynamic Thumbnail Row Switcher at Bottom */}
                  <div className="bottom-oriented-thumbnail-switcher-row">
                    {productEntity.media.map((src, idx) => (
                      <div 
                        key={idx} 
                        className={`thumbnail-switcher-node-card${idx === selectedImgIdx ? ' active-node' : ''}`}
                        onClick={() => setSelectedImgIdx(idx)}
                      >
                        <img src={src} alt="Carousel Switcher Option" />
                      </div>
                    ))}
                  </div>
                </div>

                {/* Technical Description Content Segment */}
                <div className="col-md-6 product-details-right-cell">
                  <h1 className="product-display-main-title">{productEntity.name}</h1>
                  <div className="product-display-price-badge">{productEntity.price}</div>
                  
                  <hr className="divider-line" />
                  
                  <h4 className="detail-pane-section-subtitle">Functional Summary</h4>
                  <p className="detail-pane-body-text">{productEntity.description}</p>
                  
                  <h4 className="detail-pane-section-subtitle">Technical Blueprint Specifications</h4>
                  <ul className="specs-unordered-list-stack">
                    {productEntity.specs.map((spec, index) => (
                      <li key={index} className="spec-list-item-node">{spec}</li>
                    ))}
                  </ul>

                  <button className="btn-product-intent-action" onClick={() => alert('Requirement transmission query dispatch initialized.')}>
                    Procure Solution Specifications
                  </button>
                </div>

              </div>
            </div>

            {/* SIMILAR PRODUCTS SYSTEM FEED CONTAINER */}
            <div className="product-profile-master-card">
              <h3 className="product-inner-card-heading">Similar Premium Architectural Solutions</h3>
              <div className="similar-products-vertical-list-stack">
                {Object.keys(MOCK_PRODUCT_DATABASE).filter(id => id !== productId).map(id => {
                  const item = MOCK_PRODUCT_DATABASE[id];
                  return (
                    <div key={id} className="similar-product-row-item-card" onClick={() => { navigate(`/city/${city}/${company}/product/${id}`); setSelectedImgIdx(0); }}>
                      <img src={item.media[0]} alt={item.name} className="similar-prod-thumbnail" />
                      <div className="similar-prod-details-meta">
                        <h5 className="similar-prod-title">{item.name}</h5>
                        <span className="similar-prod-price">{item.price}</span>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>

          </div>

          {/* ── RIGHT COLUMN AREA: FIXED STICKY SIDEBAR AREA ── */}
          <div className="col-lg-4 product-sidebar-fixed-pane">
            <div className="sidebar-sticky-enclosure-stack">
              
              {/* Context Module Box 1: Related Categories Layout */}
              <div className="company-sidebar-card">
                <h4 className="company-sidebar-title">Related Categories</h4>
                <div className="sidebar-vertical-navigation-links">
                  {MOCK_SIDEBAR_FALLBACK.relatedCategories.map((cat) => (
                    <div key={cat.id} className="sidebar-navigation-row-link" onClick={() => alert(cat.name)}>
                      <span className="nav-row-text-label">{cat.name}</span>
                      <i className="fas fa-chevron-right nav-row-arrow-indicator"></i>
                    </div>
                  ))}
                </div>
              </div>

              {/* Context Module Box 2: Related Keywords Layout */}
              <div className="company-sidebar-card">
                <h4 className="company-sidebar-title">Related Keywords</h4>
                <div className="sidebar-keywords-flex-matrix-dock">
                  {MOCK_SIDEBAR_FALLBACK.relatedKeywords.map((kw, i) => (
                    <span key={i} className="sidebar-keyword-pill-tag-node" onClick={() => alert(kw)}>#{kw}</span>
                  ))}
                </div>
              </div>

            </div>
          </div>

        </div>
      </div>
    </div>
  );
}
